#include <stdio.h>
#include <string.h>
#include <ctype.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        char s[1000005]; scanf("%s",s);
        int hasLow=0, hasUp=0, hasSpec=0;
        for(int i=0;i<N;i++){
            if(islower((unsigned char)s[i])) hasLow=1;
            else if(isupper((unsigned char)s[i])) hasUp=1;
            else hasSpec=1;
        }
        int missing = (!hasLow) + (!hasUp) + (!hasSpec);
        int deficit = (N<8)? 8-N : 0;
        int ans = missing>deficit? missing: deficit;
        printf("%d\n", ans);
    }
    return 0;
}

