    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        for(int t=0; t<T; t++){
            int N = Integer.parseInt(br.readLine().trim());
            String s = br.readLine();
            boolean hasLow=false, hasUp=false, hasSpec=false;
            for(int i=0;i<s.length();i++){
                char c = s.charAt(i);
                if(Character.isLowerCase(c)) hasLow=true;
                else if(Character.isUpperCase(c)) hasUp=true;
                else hasSpec=true;
            }
            int missing = (hasLow?0:1) + (hasUp?0:1) + (hasSpec?0:1);
            int deficit = N<8 ? 8 - N : 0;
            out.append(Math.max(missing, deficit)).append('\n');
        }
        System.out.print(out.toString());
    }
}

