const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const T = parseInt(lines[idx++].trim(), 10);
let results = [];
for (let t = 0; t < T; t++) {
  const N = parseInt(lines[idx++].trim(), 10);
  const s = lines[idx++] || '';
  let hasLow = false, hasUp = false, hasSpec = false;
  for (let i = 0; i < s.length; i++) {
    const ch = s[i];
    if (ch >= 'a' && ch <= 'z') hasLow = true;
    else if (ch >= 'A' && ch <= 'Z') hasUp = true;
    else hasSpec = true;
  }
  const missing = (hasLow ? 0 : 1) + (hasUp ? 0 : 1) + (hasSpec ? 0 : 1);
  const deficit = N < 8 ? 8 - N : 0;
  results.push(String(Math.max(missing, deficit)));
}
console.log(results.join('\n'));

